from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentences = []

    for subject, triples_list in subject_map.items():
        # Start with the subject
        base = subject
        details = []

        # Process each predicate with natural language patterns
        for predicate, obj in triples_list:
            if predicate == "cityServed":
                details.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                details.append(f"has a mayor of {obj}")
            elif predicate == "isPartOf":
                details.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                details.append(f"is operated by {obj}")
            elif predicate == "location":
                details.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                details.append(f"is {obj} metres above sea level")
            elif predicate == "runwayLength":
                details.append(f"has a runway length of {obj} metres")
            elif predicate == "country":
                details.append(f"is located in {obj}")
            elif predicate == "capital":
                details.append(f"has {obj} as its capital")
            elif predicate == "language":
                details.append(f"has {obj} as its official language")
            elif predicate == "leader":
                details.append(f"has {obj} as its leader")
            elif predicate == "owner":
                details.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                details.append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                details.append(f"has a first runway with {obj} surface")
            elif predicate == "3rdRunwayLengthFeet":
                details.append(f"has a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                details.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                details.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                details.append(f"is {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                details.append(f"has an IATA location identifier of {obj}")
            elif predicate == "nativeName":
                details.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                details.append(f"has a leader party of {obj}")
            elif predicate == "runwayName":
                details.append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                details.append(f"has a runway surface type of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                details.append(f"is {obj} metres above sea level")
            else:
                # For any other predicate, use a natural phrasing
                clean_predicate = predicate.replace('1stRunway', 'first runway ').replace('3rdRunway', 'third runway ').replace('Runway', ' runway ').replace('LocationIdentifier', ' location identifier')
                details.append(f"has a {clean_predicate} of {obj}")

        # Combine all details with appropriate connectors
        if details:
            if len(details) == 1:
                base += " " + details[0]
            else:
                # Use commas for most items, and "and" before the last
                base += " " + ", ".join(details[:-1]) + " and " + details[-1]
            sentences.append(base + ".")

    # Join multiple sentences with appropriate connectors
    if len(sentences) == 1:
        return sentences[0]
    else:
        # For multiple subjects, join with "Additionally," for better flow
        return " ".join(sentences)

